module binary_counter_en (
    input clk,
    input reset,
    input enable,
    output reg [3:0] count
);always @(posedge clk) begin
  wire _tap_clk = clk & {1{1'b1}};

        if (reset)
            count <= 4'b0000;
        else if (enable)
            count <= count + 1;
    end

endmodule
